:root {
  --bg: #f8f8f6;
  --ink: #171717;
  --muted: #66645e;
  --line: #d9d7d0;
  --soft-line: #ebe9e2;
  --surface: #ffffff;
  --code: #20201d;
  --accent: #0f766e;
  --accent-soft: #e0f2ef;
  --warn: #b45309;
  --warn-soft: #fff4dc;
  --risk: #b91c1c;
  --risk-soft: #fde8e8;
  --done: #166534;
  --done-soft: #e8f5e9;
  --z-base: 0;
  --z-nav: 10;
}

* {
  box-sizing: border-box;
}

html {
  background: var(--bg);
  color: var(--ink);
  font-family:
    ui-serif, Georgia, Cambria, "Times New Roman", Times, serif;
  scroll-behavior: smooth;
}

body {
  margin: 0;
  min-height: 100dvh;
}

a {
  color: inherit;
  text-decoration-color: var(--accent);
  text-decoration-thickness: 1px;
  text-underline-offset: 3px;
}

a:hover {
  color: var(--accent);
}

.topbar {
  position: sticky;
  top: 0;
  z-index: var(--z-nav);
  border-bottom: 1px solid var(--line);
  background: rgba(248, 248, 246, 0.96);
}

.topbar-inner {
  display: flex;
  max-width: 1180px;
  margin: 0 auto;
  padding: 12px 24px;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
}

.brand {
  font-family:
    ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI",
    sans-serif;
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 0;
  text-transform: uppercase;
}

nav {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 12px 18px;
  font-family:
    ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI",
    sans-serif;
  font-size: 13px;
  color: var(--muted);
}

nav a {
  text-decoration: none;
}

main {
  max-width: 1180px;
  margin: 0 auto;
  padding: 52px 24px 80px;
}

.hero {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 280px;
  gap: 48px;
  align-items: end;
  border-bottom: 2px solid var(--ink);
  padding-bottom: 34px;
}

.kicker {
  margin: 0 0 18px;
  color: var(--accent);
  font-family:
    ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI",
    sans-serif;
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 0;
  text-transform: uppercase;
}

h1,
h2,
h3 {
  margin: 0;
  letter-spacing: 0;
  text-wrap: balance;
}

h1 {
  max-width: 880px;
  font-size: clamp(42px, 7vw, 96px);
  line-height: 0.94;
  font-weight: 900;
}

h2 {
  font-size: clamp(28px, 4vw, 54px);
  line-height: 1;
  font-weight: 900;
}

h3 {
  font-family:
    ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI",
    sans-serif;
  font-size: 16px;
  line-height: 1.2;
  font-weight: 800;
}

p {
  margin: 0;
  color: var(--muted);
  font-size: 17px;
  line-height: 1.55;
  text-wrap: pretty;
}

.hero-aside {
  border-left: 1px solid var(--line);
  padding-left: 22px;
  font-family:
    ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI",
    sans-serif;
}

.stamp {
  display: block;
  color: var(--muted);
  font-size: 12px;
  font-weight: 700;
  text-transform: uppercase;
}

.date {
  display: block;
  margin-top: 4px;
  font-size: 22px;
  font-weight: 800;
  font-variant-numeric: tabular-nums;
}

.hero-links {
  display: grid;
  gap: 8px;
  margin-top: 22px;
  font-size: 14px;
}

section {
  border-bottom: 1px solid var(--line);
  padding: 46px 0;
}

.section-head {
  display: grid;
  grid-template-columns: minmax(180px, 320px) minmax(0, 1fr);
  gap: 36px;
  align-items: start;
  margin-bottom: 30px;
}

.section-head p {
  max-width: 760px;
}

.lede {
  color: var(--ink);
  font-size: 23px;
  line-height: 1.4;
}

.band {
  border-top: 1px solid var(--line);
  padding: 22px 0;
}

.band:last-child {
  border-bottom: 1px solid var(--line);
}

.split {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  gap: 24px 42px;
}

.triple {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 22px;
}

.quad {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 18px;
}

.cell {
  border-top: 4px solid var(--ink);
  padding-top: 14px;
}

.cell p,
.cell li {
  font-family:
    ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI",
    sans-serif;
  font-size: 14px;
  line-height: 1.5;
}

.label {
  display: inline-flex;
  align-items: center;
  min-height: 26px;
  border: 1px solid var(--line);
  background: var(--surface);
  padding: 3px 9px;
  font-family:
    ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI",
    sans-serif;
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
}

.label.high {
  border-color: #efb4b4;
  background: var(--risk-soft);
  color: var(--risk);
}

.label.medium {
  border-color: #f2d092;
  background: var(--warn-soft);
  color: var(--warn);
}

.label.good {
  border-color: #9fd4a4;
  background: var(--done-soft);
  color: var(--done);
}

.label.now {
  border-color: #9bd9d2;
  background: var(--accent-soft);
  color: var(--accent);
}

.change-key {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  align-items: center;
  margin-top: 16px;
  font-family:
    ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI",
    sans-serif;
  font-size: 13px;
}

ins.plan-add,
del.plan-delete {
  display: inline;
  border: 1px solid transparent;
  padding: 1px 5px;
  font-family: inherit;
  text-decoration-thickness: 1px;
  text-underline-offset: 3px;
}

ins.plan-add {
  border-color: #9bd9d2;
  background: var(--accent-soft);
  color: var(--accent);
  text-decoration: underline;
}

del.plan-delete {
  border-color: #efb4b4;
  background: var(--risk-soft);
  color: var(--risk);
  text-decoration: line-through;
}

.decision-mark {
  display: inline-flex;
  align-items: center;
  min-height: 24px;
  border: 1px solid #9bd9d2;
  background: var(--accent-soft);
  padding: 2px 8px;
