# Local Dev

`dev/scope-dev` is the supported local development entrypoint.
`dev/api` contains Rust code that is compiled only for `--features local-dev`;
it is intentionally outside `api/src` so it is not part of the production API
runtime.

```bash
./dev/scope-dev doctor
./dev/scope-dev up
./dev/scope-dev bench
./dev/scope-dev status
./dev/scope-dev down
./dev/scope-dev reset
```

The command starts:

- web at `http://localhost:3000`
- API at `http://localhost:8080`
- worker

Local API runs with `cargo run -p api --features local-dev`, Postgres metadata
seeded with demo repositories, and filesystem object storage under `.scope/dev`.
Set a safe local `DATABASE_URL` in root `.env.local`. The script strips inherited
Railway variables and refuses production-looking Clerk or database settings.

`web/.env.local` must contain Clerk development keys. The script derives
`CLERK_ISSUER` for the local API from `VITE_CLERK_PUBLISHABLE_KEY`.

Root `.env.local` must contain `SCOPE_DEV_USER_EMAIL` matching the Clerk dev
account you sign in with. `SCOPE_DEV_USER_HANDLE` is optional.

The local dev stack intentionally does not start the CLI installer service.
Seeded repositories are the default UI development path until a separate CLI dev
environment exists.

Run `./dev/scope-dev bench` while the stack is up to collect the Phase 0 local
data-architecture baseline. The benchmark harness lives under `bench/`, uses
the seeded local repos, reuses the local Scope CLI session when available, and
writes ignored reports to `.tmp/bench/phase0/`.
import {
  loadRepoFileForRequest,
  loadRepoForRequest,
  parseRepoParams,
} from '@/api/repos'
import type { RepoParams } from '@/api/types'
import { RepoDetailPage } from '@/features/repo-detail/repo-detail-page'
import {
  displayRouteFilePath,
  parseRouteFileSearch,
  routeErrorMessage,
  selectedRouteFilePath,
} from '@/lib/route-file'
import { createFileRoute, useNavigate } from '@tanstack/react-router'
import { createServerFn } from '@tanstack/react-start'

const loadRepo = createServerFn({ method: 'GET' })
  .validator(parseRepoParams)
  .handler(({ data }) => loadRepoForRequest(data))

const loadRepoFile = createServerFn({ method: 'GET' })
  .validator((data: RepoFileInput) => data)
  .handler(({ data }) => loadRepoFileForRequest(data))

export const Route = createFileRoute('/repos/$owner/$repo/')({
  validateSearch: parseRepoCodeSearch,
  loaderDeps: ({ search }) => search,
  loader: async ({ deps: search, params }) => {
    const detail = await loadRepo({ data: params })
    const selectedPath = selectedRouteFilePath(detail.files, search.file)
    let selectedFile = null
    let selectedFileError = null
    if (selectedPath) {
      try {
        selectedFile = await loadRepoFile({
          data: { ...params, path: selectedPath },
        })
      } catch (error) {
        selectedFileError = routeErrorMessage(error, 'File content is unavailable.')
      }
    }
    return { detail, selectedFile, selectedFileError, selectedPath }
  },
  component: RepoIndexRoute,
})

function RepoIndexRoute() {
  const { detail, selectedFile, selectedFileError, selectedPath } =
    Route.useLoaderData()
  const params = Route.useParams()
  const navigate = useNavigate({ from: Route.fullPath })

  return (
    <RepoDetailPage
      detail={detail}
      onSelectFile={(file) => {
        void navigate({ search: { file: displayRouteFilePath(file.path) } })
      }}
      params={params}
      selectedFile={selectedFile}
      selectedFileError={selectedFileError}
      selectedPath={selectedPath}
    />
  )
}

type RepoCodeSearch = { file?: string }
type RepoFileInput = RepoParams & { path: string }

function parseRepoCodeSearch(search: Record<string, unknown>): RepoCodeSearch {
  return { file: parseRouteFileSearch(search.file) }
}
import type {
  CommitHistory,
  ProjectionPreviewAudience,
  RepoParams,
} from '@/api/types'
import {
  HistoryError,
  HistoryPage,
  type CommitHistories,
} from '@/features/history/history-page'
import {
  loadCommitDetail,
  loadCommitHistory,
} from '@/routes/-repo-history-actions'
import { createFileRoute } from '@tanstack/react-router'

export const Route = createFileRoute('/repos/$owner/$repo/history')({
  validateSearch: parseHistorySearch,
  loaderDeps: ({ search }) => search,
  loader: async ({ deps: search, params }) => {
    const [privateHistory, publicHistory] = await Promise.all([
      loadOptionalPrivateHistory(params),
      loadPublicHistory(params),
    ])

    if (!privateHistory && !publicHistory.history) {
      throw publicHistory.error
    }

    const histories = {
      private: privateHistory,
      public: publicHistory.history,
    } satisfies CommitHistories
    const initialAudience = initialHistoryAudience(histories, search)
    const initialCommitId =
      selectedCommitId(histories[initialAudience], search.commit) ??
      latestCommitId(histories[initialAudience])
    const initialCommit = initialCommitId
      ? await loadCommitDetail({
          data: {
            ...params,
            audience: initialAudience,
            commit: initialCommitId,
          },
        })
      : null

    return {
      histories,
      initialAudience,
      initialCommit,
    }
  },
  errorComponent: HistoryError,
  component: HistoryRoute,
})

function HistoryRoute() {
  const params = Route.useParams()
  const { histories, initialAudience, initialCommit } = Route.useLoaderData()

  return (
    <HistoryPage
      histories={histories}
      initialAudience={initialAudience}
      initialCommit={initialCommit}
      key={`${initialAudience}:${initialCommit?.projected_id ?? ''}`}
      params={params}
    />
  )
}

type HistorySearch = {
  audience?: ProjectionPreviewAudience
  commit?: string
}

function parseHistorySearch(search: Record<string, unknown>): HistorySearch {
  return {
    audience: searchHistoryAudience(search.audience),
    commit: searchCommitId(search.commit),
  }
}

function searchHistoryAudience(value: unknown): ProjectionPreviewAudience | undefined {
  if (value === undefined || value === null || value === '') {
    return undefined
  }
  if (value === 'private' || value === 'public') {
    return value
  }
  throw new Error(`Unsupported history audience: ${String(value)}`)
}

function searchCommitId(value: unknown) {
  if (typeof value === 'string') {
    const commitId = value.trim()
    return commitId ? commitId : undefined
  }

  if (typeof value === 'number' && Number.isFinite(value)) {
    return String(value)
  }

  return undefined
}

async function loadOptionalPrivateHistory(params: RepoParams) {
  try {
    return await loadCommitHistory({
      data: { ...params, audience: 'private' },
    })
  } catch (error) {
    if (isForbiddenOrNotFound(error)) {
      return null
    }
    throw error
  }
}

async function loadPublicHistory(params: RepoParams): Promise<{
  error: unknown
  history: CommitHistory | null
}> {
  try {
    return {
      error: null,
      history: await loadCommitHistory({
        data: { ...params, audience: 'public' },
      }),
    }
  } catch (error) {
    return { error, history: null }
  }
}

function initialHistoryAudience(
  histories: CommitHistories,
  search: HistorySearch,
): ProjectionPreviewAudience {
  if (search.audience && histories[search.audience]) {
    return search.audience
  }
  return histories.private ? 'private' : 'public'
}

function selectedCommitId(history: CommitHistory | null, commitId?: string) {
  if (!commitId) {
    return null
  }
  return history?.commits.some((commit) => commit.projected_id === commitId)
    ? commitId
    : null
}

function latestCommitId(history: CommitHistory | null) {
  return history?.commits.at(-1)?.projected_id ?? null
}

function isForbiddenOrNotFound(error: unknown) {
  return (
    typeof error === 'object' &&
    error !== null &&
    'status' in error &&
    [403, 404].includes(Number((error as { status: unknown }).status))
  )
}
